<script setup lang="ts">
import {nextTick,ref} from 'vue';const props=withDefaults(defineProps<{title?:string;size?:'sm'|'md'|'lg'|'full';modal?:boolean;closeOnEscape?:boolean}>(),{title:'Account settings',size:'md',modal:true,closeOnEscape:true});const shown=ref(true),el=ref<HTMLDialogElement>(),trigger=ref<HTMLButtonElement>();async function show(){shown.value=true;await nextTick();if(props.modal&&!el.value?.open)el.value?.showModal()}function close(){el.value?.close();shown.value=false;trigger.value?.focus()}function cancel(e:Event){if(!props.closeOnEscape)e.preventDefault();else shown.value=false}
</script>
<template><main class="dialog-shell"><h1>Dialog</h1><section class="dialog-matrix"><button ref="trigger" type="button" @click="show">Open dialog</button><dialog ref="el" :open="shown&&!modal" :class="['kumo-dialog',size]" aria-labelledby="dialog-title" aria-describedby="dialog-description" :aria-modal="modal||undefined" @cancel="cancel" @close="shown=false"><h2 id="dialog-title">{{title}}</h2><p id="dialog-description">Dialog content and keyboard behavior preview.</p><button aria-label="Close" @click="close">×</button><div class="dialog-actions"><button @click="close">Cancel</button><button class="primary" @click="close">Confirm</button></div></dialog></section></main></template>
